dtsPropsFor.PanelChrome:
/** panel title shown in the drag-handle bar */
title: string;
/** show the link/pin symbol-lock control */
pinnable?: boolean;
/** locked symbol code, or null to follow the watchlist selection */
pin?: string | null;
/** the currently-selected code (used when locking) */
currentCode?: string | null;
onPinChange?: (pin: string | null) => void;
onRemove?: () => void;
onPopout?: () => void;
children?: React.ReactNode;

dtsPropsFor.QuoteBoard:
/** the contract to display */
contract: {
  code: string;
  name: string;
  reference: number;
  limit_up: number;
  limit_down: number;
};
/** REST snapshot fallback when no live tick has arrived */
snapshot?: {
  open?: number;
  high?: number;
  low?: number;
  close?: number;
  change_price?: number;
  change_rate?: number;
  total_volume?: number;
};

dtsPropsFor.OrderFlow:
/** the contract whose aggressive order flow is quantified */
contract: {
  code: string;
  security_type?: "FUT" | "OPT" | "STK" | "IND" | null;
  name?: string;
};

dtsPropsFor.Sparkline:
/** the contract whose intraday closes are drawn */
contract: { code: string };
/** live price appended to the series */
last?: number;
/** baseline (昨收/參考價) drawn as a dashed line; also sets the up/down color */
reference?: number;
width?: number;
height?: number;
/** fill the container width instead of the fixed `width` */
stretch?: boolean;

dtsPropsFor.TickTape:
/** the contract whose trade prints are streamed */
contract: {
  code: string;
  security_type?: "FUT" | "OPT" | "STK" | "IND" | null;
};

dtsPropsFor.VolProfile:
/** the contract whose price-by-volume profile is built */
contract: {
  code: string;
  security_type?: "FUT" | "OPT" | "STK" | "IND" | null;
};

dtsPropsFor.OptPayoff:
/** option/futures positions to chart the settlement payoff for; simulated legs can be added in-panel */
positions?: Array<{
  code: string;
  direction: "Buy" | "Sell";
  quantity: number;
  price: number;
}>;

dtsPropsFor.ChipsCard:
/** the stock to show margin/short/punish chips for (stocks only) */
contract: {
  code: string;
  name: string;
  security_type?: "STK" | "FUT" | "OPT" | "IND" | null;
  day_trade?: "Yes" | "OnlyBuy" | "No" | "";
  margin_trading_balance?: number;
  short_selling_balance?: number;
};
